/// Default number of tokens to generate per mesh chat turn. Coding prompts need
/// enough room for a complete answer; operators can lower/raise this with
/// `MOONSHINE_AGENT_GEN_TOKENS`.
const DEFAULT_GEN_TOKENS: usize = 256;
const DEFAULT_QWEN_KNOT_CACHE_NAME: &str = "qwen2.5-0.5b-instruct.knot";
const DEFAULT_QWEN_KNOT_URL: &str =
    "https://www-edgework-app.edgework.ai/api/v1/r2/distributed-inference/models/qwen2.5-0.5b-instruct.knot";
const QWEN_STOP_TOKEN_IDS: &[u32] = &[151_643, 151_645];
const QWEN_PERIOD_TOKEN_ID: u32 = 13;
/// "\n" / "\n\n" / "\n\n\n" in the qwen2.5 BPE vocab (paragraph-stop chat mode).
const QWEN_NEWLINE_TOKEN_ID: u32 = 198;
const QWEN_PARA_TOKEN_ID: u32 = 271;
const QWEN_PARA3_TOKEN_ID: u32 = 1_406;
const AGENT_EXEC_SCHEMA_VERSION: u8 = 1;
const PERMISSION_STATE_DIR: &str = ".moonshine/agent-permissions";
const RUN_LEDGER_DIR: &str = ".moonshine/agent-runs";
const TOOL_INTENT_DIR: &str = ".moonshine/agent-tools";
const MCP_SUPERSERVER_PORT: u16 = 8800;
