#[cfg(test)]
mod agent_parser_tests {
    use super::*;
    use tokio::io::{AsyncReadExt, AsyncWriteExt};

    #[test]
    fn knot_display_name_strips_directory_and_extension() {
        assert_eq!(
            knot_display_name("/tmp/models/qwen2.5-0.5b-instruct.knot"),
            "qwen2.5-0.5b-instruct"
        );
        assert_eq!(knot_display_name("no-extension-here"), "no-extension-here");
    }

    #[test]
    fn fat_station_model_display_honors_explicit_env_override() {
        std::env::set_var("MOONSHINE_LLM_KNOT", "/tmp/some-dir/custom-coder-7b.knot");
        assert_eq!(fat_station_model_display(), "custom-coder-7b");
        std::env::remove_var("MOONSHINE_LLM_KNOT");
    }

    #[test]
    fn recognizes_default_qwen_knot_names_for_auto_download() {
        assert!(is_default_qwen_knot_path(Path::new(
            "open-source/bitwise/datasets/qwen2.5-0.5b-instruct-q4_k_m.knot"
        )));
        assert!(is_default_qwen_knot_path(Path::new(
            "/tmp/qwen2.5-0.5b-instruct.knot"
        )));
        assert!(!is_default_qwen_knot_path(Path::new(
            "/tmp/custom-model.knot"
        )));
    }

    #[tokio::test]
    async fn downloads_model_knot_to_partial_then_final_cache_path() {
        let dir = tempfile::tempdir().unwrap();
        let dest = dir.path().join(DEFAULT_QWEN_KNOT_CACHE_NAME);
        let body = b"test-knot-bytes";
        let listener = tokio::net::TcpListener::bind("127.0.0.1:0")
            .await
            .unwrap();
        let addr = listener.local_addr().unwrap();
        let server = tokio::spawn(async move {
            let (mut socket, _) = listener.accept().await.unwrap();
            let mut buf = [0u8; 1024];
            let _ = socket.read(&mut buf).await.unwrap();
            let headers = format!(
                "HTTP/1.1 200 OK\r\nContent-Length: {}\r\nConnection: close\r\n\r\n",
                body.len()
            );
            socket.write_all(headers.as_bytes()).await.unwrap();
            socket.write_all(body).await.unwrap();
        });

        download_model_knot(&format!("http://{addr}/model.knot"), &dest)
            .await
            .unwrap();
        server.await.unwrap();

        assert_eq!(fs::read(&dest).unwrap(), body);
        assert!(!dest.with_extension("knot.partial").exists());
    }
}

fn emit_agent_json_event(event: AgentJsonEvent, ledger_path: Option<&Path>) -> Result<()> {
    let line = serde_json::to_string(&event)?;
    println!("{line}");
    if let Some(path) = ledger_path {
        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent)?;
        }
        let mut line_with_newline = line;
        line_with_newline.push('\n');
        fs::OpenOptions::new()
            .create(true)
            .append(true)
            .open(path)?
            .write_all(line_with_newline.as_bytes())?;
    }
    Ok(())
}

