fn parse_agent_exec_options(args_line: &str) -> Result<AgentExecOptions> {
    let words = shlex::split(args_line)
        .ok_or_else(|| anyhow!("agent exec: could not parse quoted arguments"))?;
    let mut json = false;
    let mut permission_mode = AgentPermissionMode::Ask;
    let mut provider = std::env::var("MOONSHINE_AGENT_PROVIDER")
        .ok()
        .filter(|value| !value.trim().is_empty())
        .map(|value| AgentProvider::parse(value.trim()))
        .transpose()?
        .unwrap_or(AgentProvider::Sovereign);
    let mut cwd: Option<PathBuf> = None;
    let mut max_turns: Option<usize> = None;
    let mut no_tools = false;
    let mut prompt_words: Vec<String> = Vec::new();
    let mut i = 0;
    while i < words.len() {
        match words[i].as_str() {
            "--json" => {
                json = true;
                i += 1;
            }
            "--permission-mode" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent exec: --permission-mode requires a value"))?;
                permission_mode = AgentPermissionMode::parse(value)?;
                i += 2;
            }
            "--provider" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent exec: --provider requires a value"))?;
                provider = AgentProvider::parse(value)?;
                i += 2;
            }
            "--cwd" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent exec: --cwd requires a path"))?;
                cwd = Some(PathBuf::from(value));
                i += 2;
            }
            "--max-turns" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent exec: --max-turns requires a number"))?;
                let parsed = value
                    .trim()
                    .parse::<usize>()
                    .ok()
                    .filter(|v| *v > 0)
                    .ok_or_else(|| {
                        anyhow!("agent exec: --max-turns requires a positive integer")
                    })?;
                max_turns = Some(parsed);
                i += 2;
            }
            "--no-tools" => {
                no_tools = true;
                i += 1;
            }
            "--" => {
                prompt_words.extend(words[i + 1..].iter().cloned());
                break;
            }
            flag if flag.starts_with("--") => {
                return Err(anyhow!("agent exec: unsupported flag '{}'", flag));
            }
            _ => {
                prompt_words.extend(words[i..].iter().cloned());
                break;
            }
        }
    }

    let prompt = prompt_words.join(" ").trim().to_string();
    if prompt.is_empty() {
        return Err(anyhow!(
            "agent exec: prompt is required (usage: agent exec [--json] [--permission-mode ask|read-only|auto] [--provider sovereign|codex|claude] [--cwd <path>] [--max-turns <n>] [--no-tools] <prompt>)"
        ));
    }

    Ok(AgentExecOptions {
        json,
        permission_mode,
        provider,
        cwd,
        prompt,
        max_turns,
        no_tools,
    })
}

fn parse_agent_verify_options(args_line: &str) -> Result<AgentVerifyOptions> {
    let words = shlex::split(args_line)
        .ok_or_else(|| anyhow!("agent verify: could not parse quoted arguments"))?;
    let mut json = false;
    let mut cwd: Option<PathBuf> = None;
    let mut formal_target: Option<String> = None;
    let mut i = 0;
    while i < words.len() {
        match words[i].as_str() {
            "--json" => {
                json = true;
                i += 1;
            }
            "--cwd" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent verify: --cwd requires a path"))?;
                cwd = Some(PathBuf::from(value));
                i += 2;
            }
            "--formal-target" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent verify: --formal-target requires a value"))?;
                formal_target = Some(value.clone());
                i += 2;
            }
            "--" => {
                formal_target = Some(words[i + 1..].join(" "));
                break;
            }
            flag if flag.starts_with("--") => {
                return Err(anyhow!("agent verify: unsupported flag '{}'", flag));
            }
            value => {
                formal_target = Some(value.to_string());
                i += 1;
            }
        }
    }

    let formal_target = formal_target
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .ok_or_else(|| {
            anyhow!("agent verify: --formal-target <Gnosis.Module-or-path.lean> is required")
        })?;
    Ok(AgentVerifyOptions {
        json,
        cwd,
        formal_target,
    })
}

fn parse_agent_providers_options(args_line: &str) -> Result<AgentProvidersOptions> {
    let words = shlex::split(args_line)
        .ok_or_else(|| anyhow!("agent providers: could not parse quoted arguments"))?;
    let mut json = false;
    for word in words {
        match word.as_str() {
            "--json" => json = true,
            flag if flag.starts_with("--") => {
                return Err(anyhow!("agent providers: unsupported flag '{}'", flag));
            }
            other => return Err(anyhow!("agent providers: unexpected argument '{}'", other)),
        }
    }
    Ok(AgentProvidersOptions { json })
}

fn parse_agent_runs_options(args_line: &str) -> Result<AgentRunsOptions> {
    let words = shlex::split(args_line)
        .ok_or_else(|| anyhow!("agent runs: could not parse quoted arguments"))?;
    let mut json = false;
    let mut cwd: Option<PathBuf> = None;
    let mut limit = 20usize;
    let mut i = 0;
    while i < words.len() {
        match words[i].as_str() {
            "--json" => {
                json = true;
                i += 1;
            }
            "--cwd" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent runs: --cwd requires a path"))?;
                cwd = Some(PathBuf::from(value));
                i += 2;
            }
            "--limit" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent runs: --limit requires a number"))?;
                limit = value
                    .parse::<usize>()
                    .map_err(|_| anyhow!("agent runs: --limit must be a positive number"))?
                    .clamp(1, 200);
                i += 2;
            }
            flag if flag.starts_with("--") => {
                return Err(anyhow!("agent runs: unsupported flag '{}'", flag));
            }
            other => return Err(anyhow!("agent runs: unexpected argument '{}'", other)),
        }
    }
    Ok(AgentRunsOptions { json, cwd, limit })
}

fn parse_agent_replay_options(args_line: &str) -> Result<AgentReplayOptions> {
    let words = shlex::split(args_line)
        .ok_or_else(|| anyhow!("agent replay: could not parse quoted arguments"))?;
    let mut json = false;
    let mut cwd: Option<PathBuf> = None;
    let mut run_id: Option<String> = None;
    let mut i = 0;
    while i < words.len() {
        match words[i].as_str() {
            "--json" => {
                json = true;
                i += 1;
            }
            "--cwd" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent replay: --cwd requires a path"))?;
                cwd = Some(PathBuf::from(value));
                i += 2;
            }
            "--run-id" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent replay: --run-id requires a value"))?;
                run_id = Some(value.clone());
                i += 2;
            }
            flag if flag.starts_with("--") => {
                return Err(anyhow!("agent replay: unsupported flag '{}'", flag));
            }
            other => {
                if run_id.is_none() {
                    run_id = Some(other.to_string());
                    i += 1;
                } else {
                    return Err(anyhow!("agent replay: unexpected argument '{}'", other));
                }
            }
        }
    }

    Ok(AgentReplayOptions {
        json,
        cwd,
        run_id: run_id.ok_or_else(|| anyhow!("agent replay: --run-id is required"))?,
    })
}

fn parse_agent_tools_options(args_line: &str) -> Result<AgentToolsOptions> {
    let words = shlex::split(args_line)
        .ok_or_else(|| anyhow!("agent tools: could not parse quoted arguments"))?;
    let mut json = false;
    let mut cwd: Option<PathBuf> = None;
    let mut run_id: Option<String> = None;
    let mut limit = 50usize;
    let mut i = 0;
    while i < words.len() {
        match words[i].as_str() {
            "--json" => {
                json = true;
                i += 1;
            }
            "--cwd" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent tools: --cwd requires a path"))?;
                cwd = Some(PathBuf::from(value));
                i += 2;
            }
            "--run-id" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent tools: --run-id requires a value"))?;
                run_id = Some(value.clone());
                i += 2;
            }
            "--limit" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent tools: --limit requires a number"))?;
                limit = value
                    .parse::<usize>()
                    .map_err(|_| anyhow!("agent tools: --limit must be a positive number"))?
                    .clamp(1, 500);
                i += 2;
            }
            flag if flag.starts_with("--") => {
                return Err(anyhow!("agent tools: unsupported flag '{}'", flag));
            }
            other => {
                if run_id.is_none() {
                    run_id = Some(other.to_string());
                    i += 1;
                } else {
                    return Err(anyhow!("agent tools: unexpected argument '{}'", other));
                }
            }
        }
    }
    Ok(AgentToolsOptions {
        json,
        cwd,
        run_id,
        limit,
    })
}

fn parse_agent_tool_decision_options(
    args_line: &str,
    command_name: &str,
) -> Result<AgentToolDecisionOptions> {
    let words = shlex::split(args_line)
        .ok_or_else(|| anyhow!("agent {command_name}: could not parse quoted arguments"))?;
    let mut json = false;
    let mut cwd: Option<PathBuf> = None;
    let mut run_id: Option<String> = None;
    let mut intent_id: Option<String> = None;
    let mut i = 0;
    while i < words.len() {
        match words[i].as_str() {
            "--json" => {
                json = true;
                i += 1;
            }
            "--cwd" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent {command_name}: --cwd requires a path"))?;
                cwd = Some(PathBuf::from(value));
                i += 2;
            }
            "--run-id" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent {command_name}: --run-id requires a value"))?;
                run_id = Some(value.clone());
                i += 2;
            }
            "--intent-id" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent {command_name}: --intent-id requires a value"))?;
                intent_id = Some(value.clone());
                i += 2;
            }
            flag if flag.starts_with("--") => {
                return Err(anyhow!("agent {command_name}: unsupported flag '{}'", flag));
            }
            other => {
                if run_id.is_none() {
                    run_id = Some(other.to_string());
                    i += 1;
                } else if intent_id.is_none() {
                    intent_id = Some(other.to_string());
                    i += 1;
                } else {
                    return Err(anyhow!("agent {command_name}: unexpected argument '{}'", other));
                }
            }
        }
    }

    Ok(AgentToolDecisionOptions {
        json,
        cwd,
        run_id: run_id.ok_or_else(|| anyhow!("agent {command_name}: --run-id is required"))?,
        intent_id: intent_id
            .ok_or_else(|| anyhow!("agent {command_name}: --intent-id is required"))?,
    })
}

fn extract_lean_target(text: &str) -> Option<String> {
    text.split_whitespace()
        .map(|word| {
            word.trim_matches(|c: char| {
                matches!(
                    c,
                    '"' | '\'' | '`' | ',' | ';' | ':' | ')' | '(' | '[' | ']' | '{' | '}'
                )
            })
        })
        .find(|word| word.ends_with(".lean"))
        .map(ToString::to_string)
}

fn run_ledger_dir(workspace_path: &Path) -> PathBuf {
    workspace_path.join(RUN_LEDGER_DIR)
}

fn run_ledger_path(workspace_path: &Path, run_id: &str) -> PathBuf {
    run_ledger_dir(workspace_path).join(format!("{run_id}.jsonl"))
}

fn tool_intent_dir(workspace_path: &Path, run_id: &str) -> PathBuf {
    workspace_path.join(TOOL_INTENT_DIR).join(run_id)
}

fn tool_intent_path(workspace_path: &Path, run_id: &str, intent_id: &str) -> PathBuf {
    tool_intent_dir(workspace_path, run_id).join(format!("{intent_id}.json"))
}

fn persist_tool_intent(workspace_path: &Path, record: &ToolIntentRecord) -> Result<()> {
    let path = tool_intent_path(workspace_path, &record.run_id, &record.intent_id);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    fs::write(path, serde_json::to_vec_pretty(record)?)?;
    Ok(())
}

fn load_tool_intent(
    workspace_path: &Path,
    run_id: &str,
    intent_id: &str,
) -> Result<ToolIntentRecord> {
    let path = tool_intent_path(workspace_path, run_id, intent_id);
    let bytes = fs::read(&path).map_err(|err| {
        anyhow!(
            "agent tool decision: could not read intent '{}' for run '{}': {}",
            intent_id,
            run_id,
            err
        )
    })?;
    Ok(serde_json::from_slice(&bytes)?)
}

fn tool_record_from_decision(
    run_id: &str,
    intent_id: &str,
    workspace_path: &Path,
    options: &AgentExecOptions,
    decision: &MetacogDecision,
    status: &str,
) -> ToolIntentRecord {
    ToolIntentRecord {
        schema_version: AGENT_EXEC_SCHEMA_VERSION,
        run_id: run_id.to_string(),
        intent_id: intent_id.to_string(),
        workspace_path: workspace_path.to_string_lossy().into_owned(),
        permission_mode: options.permission_mode.as_str().to_string(),
        provider: options.provider.as_str().to_string(),
        tool_name: "provider_plan".to_string(),
        requested_action: decision.requested_action.to_string(),
        risk: decision.risk.to_string(),
        formal_target: decision.formal_target.clone(),
        verification_command: decision.verification_command.clone(),
        status: status.to_string(),
        created_at: chrono::Utc::now().to_rfc3339(),
    }
}

fn tool_event_from_record(kind: &'static str, record: &ToolIntentRecord) -> AgentJsonEvent {
    let mut event = AgentJsonEvent::new(kind);
    event.run_id = Some(record.run_id.clone());
    event.workspace_path = Some(record.workspace_path.clone());
    event.permission_mode = Some(record.permission_mode.clone());
    event.provider = Some(record.provider.clone());
    event.intent_id = Some(record.intent_id.clone());
    event.tool_name = Some(record.tool_name.clone());
    event.requested_action = Some(record.requested_action.clone());
    event.risk = Some(record.risk.clone());
    event.status = Some(record.status.clone());
    event.formal_target = record.formal_target.clone();
    event.verification_command = record.verification_command.clone();
    event.content = Some(format!(
        "{} {} for {}",
        record.tool_name, record.status, record.requested_action
    ));
    event
}

fn lean_verification_command(target: &str) -> String {
    format!("lake build {}", lean_module_from_target(target))
}

fn lean_module_from_target(target: &str) -> String {
    let trimmed = target.trim().trim_end_matches(".lean");
    if trimmed.starts_with("Gnosis.") {
        return trimmed.to_string();
    }
    if let Some(suffix) = trimmed.split("Gnosis/").nth(1) {
        return format!("Gnosis.{}", suffix.replace('/', "."));
    }
    trimmed.replace('/', ".")
}

fn resolve_gnosis_math_workdir(cwd: &Path) -> PathBuf {
    if cwd.join("lakefile.lean").exists() || cwd.join("lakefile.toml").exists() {
        return cwd.to_path_buf();
    }
    for ancestor in cwd.ancestors() {
        let candidate = ancestor.join("open-source/gnosis-math");
        if candidate.join("lakefile.lean").exists() || candidate.join("lakefile.toml").exists() {
            return candidate;
        }
    }
    let manifest_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    for ancestor in manifest_dir.ancestors() {
        let candidate = ancestor.join("gnosis-math");
        if candidate.join("lakefile.lean").exists() || candidate.join("lakefile.toml").exists() {
            return candidate;
        }
        let candidate = ancestor.join("open-source/gnosis-math");
        if candidate.join("lakefile.lean").exists() || candidate.join("lakefile.toml").exists() {
            return candidate;
        }
    }
    cwd.to_path_buf()
}

fn account_provider_program(provider: &AgentProvider) -> String {
    let name = provider.as_str();
    if let Ok(path) = which::which(name) {
        return path.to_string_lossy().into_owned();
    }
    if matches!(provider, AgentProvider::Claude) {
        if let Some(path) = home::home_dir()
            .map(|home| home.join(".local/bin/claude"))
            .filter(|path| path.is_file())
        {
            return path.to_string_lossy().into_owned();
        }
    }
    name.to_string()
}

fn command_status(command: &str, args: &[&str]) -> (bool, String) {
    match Command::new(command).args(args).output() {
        Ok(output) => {
            let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
            let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
            let detail = if stdout.is_empty() { stderr } else { stdout };
            (output.status.success(), detail)
        }
        Err(err) => (false, err.to_string()),
    }
}

fn run_lean_verifier_json(
    run_id: &str,
    cwd: &Path,
    formal_target: &str,
    provider: Option<&str>,
    ledger_path: Option<&Path>,
) -> Result<()> {
    let workdir = resolve_gnosis_math_workdir(cwd);
    let module = lean_module_from_target(formal_target);
    let verification_command = format!("lake build {module}");

    let mut request = AgentJsonEvent::new("tool_request");
    request.run_id = Some(run_id.to_string());
    request.workspace_path = Some(cwd.to_string_lossy().into_owned());
    request.provider = provider.map(ToString::to_string);
    request.tool_name = Some("lean_build".to_string());
    request.command = Some(verification_command.clone());
    request.path = Some(workdir.to_string_lossy().into_owned());
    request.requested_action = Some("Lean formal admission".to_string());
    request.risk = Some("formal_claim".to_string());
    request.formal_target = Some(formal_target.to_string());
    request.verification_command = Some(verification_command.clone());
    emit_agent_json_event(request, ledger_path)?;

    let started = Instant::now();
    let output = Command::new("lake")
        .current_dir(&workdir)
        .arg("build")
        .arg(&module)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .output();
    let duration_ms = started.elapsed().as_millis();

    let mut result = AgentJsonEvent::new("tool_result");
    result.run_id = Some(run_id.to_string());
    result.workspace_path = Some(cwd.to_string_lossy().into_owned());
    result.provider = provider.map(ToString::to_string);
    result.tool_name = Some("lean_build".to_string());
    result.command = Some(verification_command.clone());
    result.path = Some(workdir.to_string_lossy().into_owned());
    result.requested_action = Some("Lean formal admission".to_string());
    result.risk = Some("formal_claim".to_string());
    result.duration_ms = Some(duration_ms);
    result.formal_target = Some(formal_target.to_string());
    result.verification_command = Some(verification_command.clone());

    match output {
        Ok(output) => {
            result.status = Some(if output.status.success() {
                "passed".to_string()
            } else {
                "failed".to_string()
            });
            result.exit_code = output.status.code();
            let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
            let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
            let content = match (stdout.is_empty(), stderr.is_empty()) {
                (false, false) => format!("{stdout}\n{stderr}"),
                (false, true) => stdout,
                (true, false) => stderr,
                (true, true) => format!("{verification_command} completed with no output"),
            };
            result.content = Some(content.clone());
            emit_agent_json_event(result, ledger_path)?;

            if output.status.success() {
                Ok(())
            } else {
                let mut error = AgentJsonEvent::new("error");
                error.run_id = Some(run_id.to_string());
                error.workspace_path = Some(cwd.to_string_lossy().into_owned());
                error.provider = provider.map(ToString::to_string);
                error.requested_action = Some("Lean formal admission".to_string());
                error.risk = Some("formal_claim".to_string());
                error.formal_target = Some(formal_target.to_string());
                error.verification_command = Some(verification_command.clone());
                error.error = Some(content);
                emit_agent_json_event(error, ledger_path)?;
                Err(anyhow!("{verification_command} failed for {formal_target}"))
            }
        }
        Err(err) => {
            result.status = Some("failed".to_string());
            result.error = Some(err.to_string());
            emit_agent_json_event(result, ledger_path)?;

            let mut error = AgentJsonEvent::new("error");
            error.run_id = Some(run_id.to_string());
            error.workspace_path = Some(cwd.to_string_lossy().into_owned());
            error.provider = provider.map(ToString::to_string);
            error.requested_action = Some("Lean formal admission".to_string());
            error.risk = Some("formal_claim".to_string());
            error.formal_target = Some(formal_target.to_string());
            error.verification_command = Some(verification_command);
            error.error = Some(err.to_string());
            emit_agent_json_event(error, ledger_path)?;
            Err(anyhow!("agent verify could not run lake: {}", err))
        }
    }
}

fn classify_agent_risk(event_log: &str) -> (&'static str, &'static str) {
    let lower = event_log.to_lowercase();
    if lower.contains(".lean")
        || lower.contains("formal_claim")
        || lower.contains("prove ")
        || lower.contains("theorem")
    {
        return ("formal_claim", "Lean formal admission");
    }
    if lower.contains("rm -rf")
        || lower.contains("destructive")
        || lower.contains("delete ")
        || lower.contains("remove ")
        || lower.contains("wipe ")
    {
        return ("destructive", "destructive filesystem action");
    }
    if lower.contains("curl ")
        || lower.contains("http://")
        || lower.contains("https://")
        || lower.contains("network")
    {
        return ("network", "network access");
    }
    if lower.contains("git commit")
        || lower.contains("git push")
        || lower.contains("git checkout")
        || lower.contains("git reset")
        || lower.contains("vcs")
    {
        return ("vcs_mutation", "VCS mutation");
    }
    if lower.contains("write ")
        || lower.contains("edit ")
        || lower.contains("patch ")
        || lower.contains("create ")
        || lower.contains("modify ")
        || lower.contains("workspace_write")
    {
        return ("workspace_write", "workspace write");
    }
    ("read_only", "read-only analysis")
}

fn decide_metacog_for_mode(event_log: &str, mode: &AgentPermissionMode) -> MetacogDecision {
    let lower = event_log.to_lowercase();
    let (risk, requested_action) = classify_agent_risk(event_log);
    let formal_target = extract_lean_target(event_log);
    let verification_command = formal_target
        .as_deref()
        .map(lean_verification_command)
        .or_else(|| {
            if risk == "formal_claim" {
                Some("lake build <touched Gnosis module>".to_string())
            } else {
                None
            }
        });

    if lower.contains("malformed_contract") || lower.contains("contract_violation") {
        return MetacogDecision {
            verdict: "veto",
            reason: "client or provider contract violation must fail closed".to_string(),
            risk,
            requested_action,
            formal_target,
            verification_command,
        };
    }

    if matches!(mode, AgentPermissionMode::ReadOnly)
        && matches!(
            risk,
            "workspace_write" | "destructive" | "network" | "vcs_mutation"
        )
    {
        return MetacogDecision {
            verdict: "veto",
            reason: "read-only permission mode forbids this requested action".to_string(),
            risk,
            requested_action,
            formal_target,
            verification_command,
        };
    }

    if risk == "formal_claim" {
        return MetacogDecision {
            verdict: "reflect",
            reason: "Lean formal work requires an explicit verification target before finalizing"
                .to_string(),
            risk,
            requested_action,
            formal_target,
            verification_command,
        };
    }

    if matches!(risk, "destructive" | "network" | "vcs_mutation") {
        return MetacogDecision {
            verdict: "escalate",
            reason: "destructive or network-risk signal requires human admission".to_string(),
            risk,
            requested_action,
            formal_target,
            verification_command,
        };
    }

    if lower.contains("permission_request")
        || lower.contains("human_required")
        || lower.contains("system2")
    {
        return MetacogDecision {
            verdict: "escalate",
            reason: "secondary metacog chain requests human permission".to_string(),
            risk,
            requested_action,
            formal_target,
            verification_command,
        };
    }
    if lower.matches("stall").count() >= 2 || lower.contains("oracle_stall") {
        return MetacogDecision {
            verdict: "defer",
            reason: "stall evidence crossed the metacog defer threshold".to_string(),
            risk,
            requested_action,
            formal_target,
            verification_command,
        };
    }
    if lower.matches("no_gain").count() >= 1 || lower.contains("plateau") {
        return MetacogDecision {
            verdict: "reflect",
            reason: "non-improving step must expose shadow before continuing".to_string(),
            risk,
            requested_action,
            formal_target,
            verification_command,
        };
    }
    if !lower.contains("fold") && lower.contains("assistant_delta") {
        return MetacogDecision {
            verdict: "fold",
            reason: "assistant output observed before a fold checkpoint".to_string(),
            risk,
            requested_action,
            formal_target,
            verification_command,
        };
    }
    MetacogDecision {
        verdict: "proceed",
        reason: "metacog admission passed for this bounded event log".to_string(),
        risk,
        requested_action,
        formal_target,
        verification_command,
    }
}

fn decide_metacog(event_log: &str) -> MetacogDecision {
    decide_metacog_for_mode(event_log, &AgentPermissionMode::Ask)
}

fn agent_exec_answer(prompt: &str, decision: &MetacogDecision) -> String {
    format!(
        "Moonshine agent accepted the coding prompt under metacog verdict `{}`. Prompt: {}",
        decision.verdict,
        prompt.trim()
    )
}

fn account_provider_prompt(prompt: &str, decision: &MetacogDecision) -> String {
    let verification = decision
        .verification_command
        .as_deref()
        .unwrap_or("no formal verification target");
    format!(
        "You are running behind Moonshine's metacog admission gate. \
Do not edit files or run tools. Return a concise coding-agent response only.\n\
metacog verdict: {}\n\
risk: {}\n\
requested action: {}\n\
verification: {}\n\n\
user prompt:\n{}",
        decision.verdict,
        decision.risk,
        decision.requested_action,
        verification,
        prompt.trim()
    )
}

fn run_account_provider(
    provider: &AgentProvider,
    cwd: &Path,
    prompt: &str,
    decision: &MetacogDecision,
) -> Result<String> {
    let provider_prompt = account_provider_prompt(prompt, decision);
    let output = match provider {
        AgentProvider::Sovereign => return Ok(agent_exec_answer(prompt, decision)),
        AgentProvider::Codex => Command::new(account_provider_program(provider))
            .current_dir(cwd)
            .arg("exec")
            .arg("--cd")
            .arg(cwd)
            .arg("--sandbox")
            .arg("read-only")
            .arg("--ephemeral")
            .arg(provider_prompt)
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .output()
            .map_err(|err| anyhow!("codex provider unavailable: {}", err))?,
        AgentProvider::Claude => Command::new(account_provider_program(provider))
            .current_dir(cwd)
            .arg("--print")
            .arg("--permission-mode")
            .arg("plan")
            .arg("--output-format")
            .arg("text")
            .arg(format!("--add-dir={}", cwd.display()))
            .arg(provider_prompt)
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .output()
            .map_err(|err| anyhow!("claude provider unavailable: {}", err))?,
    };

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
        return Err(anyhow!(
            "{} provider exited with status {}{}",
            provider.as_str(),
            output.status,
            if stderr.is_empty() {
                String::new()
            } else {
                format!(": {}", stderr)
            }
        ));
    }

    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
    if stdout.is_empty() {
        return Err(anyhow!("{} provider returned no output", provider.as_str()));
    }
    Ok(stdout)
}

fn permission_state_dir(workspace_path: &Path) -> PathBuf {
    workspace_path.join(PERMISSION_STATE_DIR)
}

fn permission_record_path(workspace_path: &Path, run_id: &str) -> PathBuf {
    permission_state_dir(workspace_path).join(format!("{run_id}.json"))
}

fn persist_permission_record(
    workspace_path: &Path,
    run_id: &str,
    options: &AgentExecOptions,
    decision: &MetacogDecision,
) -> Result<()> {
    let dir = permission_state_dir(workspace_path);
    fs::create_dir_all(&dir)?;
    let record = PermissionRecord {
        schema_version: AGENT_EXEC_SCHEMA_VERSION,
        run_id: run_id.to_string(),
        workspace_path: workspace_path.to_string_lossy().into_owned(),
        permission_mode: options.permission_mode.as_str().to_string(),
        provider: options.provider.as_str().to_string(),
        prompt: options.prompt.clone(),
        verdict: decision.verdict.to_string(),
        reason: decision.reason.clone(),
        requested_action: decision.requested_action.to_string(),
        risk: decision.risk.to_string(),
        formal_target: decision.formal_target.clone(),
        verification_command: decision.verification_command.clone(),
        status: "pending".to_string(),
        created_at: chrono::Utc::now().to_rfc3339(),
    };
    let bytes = serde_json::to_vec_pretty(&record)?;
    fs::write(permission_record_path(workspace_path, run_id), bytes)?;
    Ok(())
}

fn load_permission_record(workspace_path: &Path, run_id: &str) -> Result<PermissionRecord> {
    let path = permission_record_path(workspace_path, run_id);
    let bytes = fs::read(&path)
        .map_err(|err| anyhow!("agent resume: could not read pending run '{}': {}", run_id, err))?;
    Ok(serde_json::from_slice(&bytes)?)
}

fn remove_permission_record(workspace_path: &Path, run_id: &str) -> Result<()> {
    let path = permission_record_path(workspace_path, run_id);
    if path.exists() {
        fs::remove_file(path)?;
    }
    Ok(())
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum ResumeDecision {
    Approve,
    Deny,
}

impl ResumeDecision {
    fn parse(value: &str) -> Result<Self> {
        match value {
            "approve" | "approved" => Ok(Self::Approve),
            "deny" | "denied" => Ok(Self::Deny),
            other => Err(anyhow!(
                "unknown resume decision '{}'; expected approve or deny",
                other
            )),
        }
    }

    fn as_str(&self) -> &'static str {
        match self {
            Self::Approve => "approve",
            Self::Deny => "deny",
        }
    }
}

#[derive(Debug, Clone)]
struct AgentResumeOptions {
    json: bool,
    cwd: Option<PathBuf>,
    run_id: String,
    decision: ResumeDecision,
}

fn parse_agent_resume_options(args_line: &str) -> Result<AgentResumeOptions> {
    let words = shlex::split(args_line)
        .ok_or_else(|| anyhow!("agent resume: could not parse quoted arguments"))?;
    let mut json = false;
    let mut cwd: Option<PathBuf> = None;
    let mut run_id: Option<String> = None;
    let mut decision: Option<ResumeDecision> = None;
    let mut i = 0;
    while i < words.len() {
        match words[i].as_str() {
            "--json" => {
                json = true;
                i += 1;
            }
            "--cwd" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent resume: --cwd requires a path"))?;
                cwd = Some(PathBuf::from(value));
                i += 2;
            }
            "--run-id" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent resume: --run-id requires a value"))?;
                run_id = Some(value.clone());
                i += 2;
            }
            "--decision" => {
                let value = words
                    .get(i + 1)
                    .ok_or_else(|| anyhow!("agent resume: --decision requires a value"))?;
                decision = Some(ResumeDecision::parse(value)?);
                i += 2;
            }
            flag if flag.starts_with("--") => {
                return Err(anyhow!("agent resume: unsupported flag '{}'", flag));
            }
            other => {
                if run_id.is_none() {
                    run_id = Some(other.to_string());
                    i += 1;
                } else if decision.is_none() {
                    decision = Some(ResumeDecision::parse(other)?);
                    i += 1;
                } else {
                    return Err(anyhow!("agent resume: unexpected argument '{}'", other));
                }
            }
        }
    }

    Ok(AgentResumeOptions {
        json,
        cwd,
        run_id: run_id.ok_or_else(|| anyhow!("agent resume: --run-id is required"))?,
        decision: decision.ok_or_else(|| anyhow!("agent resume: --decision is required"))?,
    })
}

#[cfg(test)]
mod tests {
    use super::{clean_chat_text, decide_metacog, parse_agent_exec_options, qwen_chat_prompt};

    #[test]
    fn qwen_chat_prompt_wraps_question_without_answering_it() {
        let prompt = qwen_chat_prompt("what is the capital of France?");

        assert!(prompt.contains("Answer the user directly and concisely."));
        assert!(prompt.contains("User: what is the capital of France?"));
        assert!(prompt.ends_with("Answer:"));
        assert!(!prompt.contains("Paris"));
    }

    #[test]
    fn clean_chat_text_strips_chat_markers_and_followup_turns() {
        assert_eq!(
            clean_chat_text("The capital of France is Paris.<|im_end|>\nUser: again"),
            "The capital of France is Paris."
        );
        assert_eq!(
            clean_chat_text("Red, blue, and yellow.\nHuman: continue"),
            "Red, blue, and yellow."
        );
        assert_eq!(
            clean_chat_text("<｜begin▁of▁sentence｜> noisy preamble"),
            ""
        );
    }

    #[test]
    fn agent_exec_parser_accepts_json_cwd_and_prompt() {
        let parsed = parse_agent_exec_options(
            "--json --permission-mode read-only --provider codex --cwd /tmp/work 'fix the test'",
        )
        .expect("parse agent exec options");

        assert!(parsed.json);
        assert_eq!(parsed.permission_mode.as_str(), "read-only");
        assert_eq!(parsed.provider.as_str(), "codex");
        assert_eq!(parsed.cwd.unwrap().to_string_lossy(), "/tmp/work");
        assert_eq!(parsed.prompt, "fix the test");
    }

    #[test]
    fn metacog_reflects_on_no_gain_and_escalates_destructive_signal() {
        let reflect = decide_metacog(
            r#"{"type":"tool_result","status":"no_gain","content":"plateau"}"#,
        );
        assert_eq!(reflect.verdict, "reflect");

        let escalate = decide_metacog(
            r#"{"type":"permission_request","command":"rm -rf target"}"#,
        );
        assert_eq!(escalate.verdict, "escalate");
    }
}

/// Resolve the fat-station port. Honors FAT_STATION_PORT (so callers can point
/// at a dedicated station, e.g. 8801) and otherwise defaults to 8000.
fn fat_station_port() -> u16 {
    std::env::var("FAT_STATION_PORT")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(8000)
}

/// Resolve the GGUF whose Qwen-family vocab the fat-station should load for
/// `POST /detokenize`. The fat-station reads this via the `TOKENIZER_GGUF_PATH`
/// env var. Resolution order:
///   1. `MOONSHINE_TOKENIZER_GGUF` env var, if set (no existence check — an
///      explicit override is honored verbatim so the operator gets a clear
///      error from the station if it is wrong).
///   2. `~/.edgework/models/Qwen2.5-0.5B-Instruct-Q4_K_M.gguf`, if it exists
///      (small, fast to load).
///   3. The deepseek-r1-qwen3-8b GGUF (Qwen-family base vocab), if it exists.
///   4. None — caller skips /detokenize and falls back to printing token ids.
fn resolve_tokenizer_gguf() -> Option<PathBuf> {
    if let Ok(explicit) = std::env::var("MOONSHINE_TOKENIZER_GGUF") {
        let trimmed = explicit.trim();
        if !trimmed.is_empty() {
            return Some(PathBuf::from(trimmed));
        }
    }

    let mut candidates: Vec<PathBuf> = Vec::new();
    if let Some(home) = std::env::var_os("HOME") {
        let home = PathBuf::from(home);
        candidates.push(home.join(".edgework/models/Qwen2.5-0.5B-Instruct-Q4_K_M.gguf"));
    }
    candidates.push(PathBuf::from(
        "/Users/buley/Library/CloudStorage/GoogleDrive-taylorbuley@gmail.com/My Drive/models/deepseek-r1-qwen3-8b-q4_k_m.gguf",
    ));

    candidates.into_iter().find(|p| p.exists())
}

pub async fn run_agent_session(config: &Config) -> Result<()> {
    println!("--- Moonshine Agentic Runtime ---");

    // 1. Cluster Detection & Warming
    let port = fat_station_port();
    let fat_station_warm = is_port_open(port).await;
    if !fat_station_warm {
        println!(
            "Inference cluster (fat-station:{}) is cold. Warming up...",
            port
        );
        warm_fat_station(config).await?;
    } else {
        // Warmed by a prior/other process — we don't know FOR CERTAIN which
        // knot it loaded, but this is the one our own config/env would pick,
        // so it's the best available answer to "which model is running."
        println!(
            "Inference cluster (fat-station:{}) is warm (model={}).",
            port,
            fat_station_model_display()
        );
    }

    let mcp_warm = is_mcp_superserver_ready().await;
    if !mcp_warm {
        println!(
            "MCP superserver ({}) is cold or not handshaking. Warming up...",
            MCP_SUPERSERVER_PORT
        );
        warm_mcp_superserver().await?;
    } else {
        println!("MCP superserver ({}) is warm.", MCP_SUPERSERVER_PORT);
    }

    let tool_index = match load_agent_tool_index().await {
        Ok(index) => {
            println!("MCP tool index loaded ({} tool(s)).", index.tools.len());
            Some(index)
        }
        Err(error) => {
            eprintln!(
                "WARNING: MCP tool index UNAVAILABLE ({}). The agent will answer \
                 WITHOUT tools (plain chat) until the superserver on :{} handshakes. \
                 Force a re-warm: `lsof -ti:{} | xargs kill` then relaunch.",
                error, MCP_SUPERSERVER_PORT, MCP_SUPERSERVER_PORT
            );
            None
        }
    };

    // 2. Interactive Session
    println!("\nDropping into agentic session. Type 'exit' to return to Moonshine shell.");
    println!("Slash commands: /tools, /tool, /suggest, /model, /model list.");

    let mut rl = DefaultEditor::new()?;
    // Rolling (user, assistant) transcript for follow-up turns; the loop keeps
    // only the last few exchanges to bound prompt growth.
    let mut chat_history: Vec<(String, String)> = Vec::new();
    // Session-pinned brain/model override set via `/model`; `None` means keep
    // re-deriving the brain from env every turn (the default behavior).
    let mut model_override: Option<(BrainKind, Option<String>)> = None;

    loop {
        let readline = rl.readline("agent> ");
        match readline {
            Ok(line) => {
                let trimmed = line.trim();
                if trimmed == "exit" || trimmed == "quit" {
                    break;
                }
                if trimmed.is_empty() {
                    continue;
                }
                rl.add_history_entry(trimmed)?;

                if let Err(e) = handle_agent_chat(
                    trimmed,
                    config,
                    tool_index.as_ref(),
                    &mut chat_history,
                    &mut model_override,
                )
                .await
                {
                    eprintln!("Agent Error: {}", e);
                }
            }
            Err(ReadlineError::Interrupted) => {
                println!("Interrupted");
                break;
            }
            Err(ReadlineError::Eof) => {
                println!("EOF");
                break;
            }
            Err(err) => {
                return Err(anyhow!("Readline error: {:?}", err));
            }
        }
    }

    Ok(())
}

pub async fn run_agent_exec_command(config: &Config, args_line: &str) -> Result<()> {
    let options = parse_agent_exec_options(args_line)?;
    let cwd = options.cwd.clone().unwrap_or(std::env::current_dir()?);
    let run_id = format!("moonshine-agent-{}", chrono::Utc::now().timestamp_millis());
    let intent_id = format!("{run_id}-intent-1");
    let ledger_path = run_ledger_path(&cwd, &run_id);
    let event_log = format!(
        "run_start prompt={} permission_mode={} workspace_path={} risk={}",
        options.prompt,
        options.permission_mode.as_str(),
        cwd.display(),
        classify_agent_risk(&options.prompt).0
    );
    let decision = decide_metacog_for_mode(&event_log, &options.permission_mode);

    if options.json {
        let mut start = AgentJsonEvent::new("run_start");
        start.run_id = Some(run_id.clone());
        start.workspace_path = Some(cwd.to_string_lossy().into_owned());
        start.permission_mode = Some(options.permission_mode.as_str().to_string());
        start.provider = Some(options.provider.as_str().to_string());
        start.prompt = Some(options.prompt.clone());
        start.requested_action = Some(decision.requested_action.to_string());
        start.risk = Some(decision.risk.to_string());
        attach_formal_metadata(&mut start, &decision);
        emit_agent_json_event(start, Some(&ledger_path))?;

        let mut metacog = AgentJsonEvent::new("metacog_verdict");
        metacog.run_id = Some(run_id.clone());
        metacog.provider = Some(options.provider.as_str().to_string());
        metacog.verdict = Some(decision.verdict.to_string());
        metacog.reason = Some(decision.reason.clone());
        metacog.requested_action = Some(decision.requested_action.to_string());
        metacog.risk = Some(decision.risk.to_string());
        attach_formal_metadata(&mut metacog, &decision);
        emit_agent_json_event(metacog, Some(&ledger_path))?;

        let mut provider_intent = AgentJsonEvent::new("provider_intent");
        provider_intent.run_id = Some(run_id.clone());
        provider_intent.workspace_path = Some(cwd.to_string_lossy().into_owned());
        provider_intent.permission_mode = Some(options.permission_mode.as_str().to_string());
        provider_intent.provider = Some(options.provider.as_str().to_string());
        provider_intent.intent_id = Some(intent_id.clone());
        provider_intent.tool_name = Some("provider_plan".to_string());
        provider_intent.status = Some("proposed".to_string());
        provider_intent.requested_action = Some(decision.requested_action.to_string());
        provider_intent.risk = Some(decision.risk.to_string());
        attach_formal_metadata(&mut provider_intent, &decision);
        provider_intent.content = Some(format!(
            "{} provider intends {} under metacog verdict {}",
            options.provider.as_str(),
            decision.requested_action,
            decision.verdict
        ));
        emit_agent_json_event(provider_intent, Some(&ledger_path))?;

        if decision.verdict == "escalate" {
            let pending = tool_record_from_decision(
                &run_id,
                &intent_id,
                &cwd,
                &options,
                &decision,
                "pending",
            );
            persist_tool_intent(&cwd, &pending)?;
            emit_agent_json_event(
                tool_event_from_record("tool_admission", &pending),
                Some(&ledger_path),
            )?;
            persist_permission_record(&cwd, &run_id, &options, &decision)?;
            let mut permission = AgentJsonEvent::new("permission_request");
            permission.run_id = Some(run_id.clone());
            permission.provider = Some(options.provider.as_str().to_string());
            permission.verdict = Some(decision.verdict.to_string());
            permission.reason = Some(decision.reason.clone());
            permission.requested_action = Some(decision.requested_action.to_string());
            permission.risk = Some(decision.risk.to_string());
            permission.status = Some("pending".to_string());
            permission.choices = Some(vec!["approve_once".to_string(), "deny".to_string()]);
            attach_formal_metadata(&mut permission, &decision);
            emit_agent_json_event(permission, Some(&ledger_path))?;

            let mut error = AgentJsonEvent::new("error");
            error.run_id = Some(run_id);
            error.provider = Some(options.provider.as_str().to_string());
            error.verdict = Some(decision.verdict.to_string());
            error.requested_action = Some(decision.requested_action.to_string());
            error.risk = Some(decision.risk.to_string());
            attach_formal_metadata(&mut error, &decision);
            error.error = Some(decision.reason.clone());
            emit_agent_json_event(error, Some(&ledger_path))?;
            return Err(anyhow!("metacog {}: {}", decision.verdict, decision.reason));
        }

        if decision.verdict == "veto" {
            let denied = tool_record_from_decision(
                &run_id,
                &intent_id,
                &cwd,
                &options,
                &decision,
                "denied",
            );
            emit_agent_json_event(
                tool_event_from_record("tool_denial", &denied),
                Some(&ledger_path),
            )?;
            let mut error = AgentJsonEvent::new("error");
            error.run_id = Some(run_id);
            error.provider = Some(options.provider.as_str().to_string());
            error.verdict = Some(decision.verdict.to_string());
            error.reason = Some(decision.reason.clone());
            error.requested_action = Some(decision.requested_action.to_string());
            error.risk = Some(decision.risk.to_string());
            attach_formal_metadata(&mut error, &decision);
            error.error = Some(decision.reason.clone());
            emit_agent_json_event(error, Some(&ledger_path))?;
            return Err(anyhow!("metacog {}: {}", decision.verdict, decision.reason));
        }

        if decision.risk == "formal_claim" && decision.formal_target.is_none() {
            let reason = "formal claim requires an explicit Lean target before finalizing";
            let denied = tool_record_from_decision(
                &run_id,
                &intent_id,
                &cwd,
                &options,
                &decision,
                "denied",
            );
            emit_agent_json_event(
                tool_event_from_record("tool_denial", &denied),
                Some(&ledger_path),
            )?;
            let mut error = AgentJsonEvent::new("error");
            error.run_id = Some(run_id);
            error.provider = Some(options.provider.as_str().to_string());
            error.verdict = Some("veto".to_string());
            error.reason = Some(reason.to_string());
            error.requested_action = Some("Lean formal admission".to_string());
            error.risk = Some("formal_claim".to_string());
            error.error = Some(reason.to_string());
            emit_agent_json_event(error, Some(&ledger_path))?;
            return Err(anyhow!(reason));
        }

        let admitted = tool_record_from_decision(
            &run_id,
            &intent_id,
            &cwd,
            &options,
            &decision,
            "admitted",
        );
        emit_agent_json_event(
            tool_event_from_record("tool_admission", &admitted),
            Some(&ledger_path),
        )?;
        let mut checkpoint = tool_event_from_record("run_checkpoint", &admitted);
        checkpoint.content = Some("provider intent admitted by Moonshine".to_string());
        emit_agent_json_event(checkpoint, Some(&ledger_path))?;

        // Sovereign provider: run the model-driven tool loop instead of the
        // legacy canned answer. NDJSON events for every tool step interleave
        // with the run envelope emitted above. MOONSHINE_AGENT_TOOL_LOOP=0
        // restores the legacy stub exactly.
        let answer_result = if options.provider == AgentProvider::Sovereign
            && agent_tool_loop_enabled()
        {
            let tool_index = if options.no_tools {
                None
            } else {
                load_agent_tool_index().await.ok()
            };
            let loop_cfg = AgentLoopConfig {
                run_id: run_id.clone(),
                permission_mode: options.permission_mode.clone(),
                provider: options.provider.as_str().to_string(),
                max_turns: options.max_turns.unwrap_or_else(agent_loop::max_turns_default),
                max_tool_calls: agent_loop::max_tool_calls_default(),
                max_stamina: agent_economy::max_stamina_default(),
                json_events: true,
                ledger_path: Some(ledger_path.clone()),
                workspace: cwd.clone(),
                interactive: false,
            };
            let brain = Brain::from_env();
            match agent_loop::run_agent_turn(
                &options.prompt,
                &[],
                tool_index.as_ref(),
                &brain,
                &loop_cfg,
            )
            .await
            {
                Ok((LoopOutcome::NeedsApproval { intent_id }, _economy)) => Err(anyhow!(
                    "tool intent {} awaits approval (agentic approve-tool --run-id {} --intent-id {})",
                    intent_id,
                    run_id,
                    intent_id
                )),
                Ok((outcome, economy)) => {
                    eprintln!(
                        "[agent] power {}/{} | score {}{}",
                        economy.weight,
                        economy.ceiling,
                        economy.score,
                        if economy.winded { " | WINDED" } else { "" }
                    );
                    Ok(outcome
                        .text()
                        .unwrap_or("(no answer produced)")
                        .to_string())
                }
                // No brain reachable: degrade to the legacy canned answer so
                // offline `agentic exec --json` keeps its always-succeeds
                // contract instead of dying on mesh availability.
                Err(err) => {
                    eprintln!("[agent] loop unavailable ({err}); using canned sovereign answer");
                    Ok(agent_exec_answer(&options.prompt, &decision))
                }
            }
        } else {
            run_account_provider(&options.provider, &cwd, &options.prompt, &decision)
        };
        let answer = match answer_result {
            Ok(answer) => answer,
            Err(err) => {
                let mut error = AgentJsonEvent::new("error");
                error.run_id = Some(run_id);
                error.provider = Some(options.provider.as_str().to_string());
                error.verdict = Some("veto".to_string());
                error.reason = Some("selected account provider failed".to_string());
                error.requested_action = Some(decision.requested_action.to_string());
                error.risk = Some(decision.risk.to_string());
                attach_formal_metadata(&mut error, &decision);
                error.error = Some(err.to_string());
                emit_agent_json_event(error, Some(&ledger_path))?;
                return Err(err);
            }
        };
        let mut delta = AgentJsonEvent::new("assistant_delta");
        delta.run_id = Some(run_id.clone());
        delta.provider = Some(options.provider.as_str().to_string());
        delta.content = Some(answer.clone());
        emit_agent_json_event(delta, Some(&ledger_path))?;

        if let Some(formal_target) = &decision.formal_target {
            run_lean_verifier_json(
                &run_id,
                &cwd,
                formal_target,
                Some(options.provider.as_str()),
                Some(&ledger_path),
            )?;
        }

        let mut final_event = AgentJsonEvent::new("final");
        final_event.run_id = Some(run_id);
        final_event.provider = Some(options.provider.as_str().to_string());
        attach_formal_metadata(&mut final_event, &decision);
        final_event.content = Some(answer);
        emit_agent_json_event(final_event, Some(&ledger_path))?;
        return Ok(());
    }

    println!("--- Moonshine Coding Agent ---");
    println!("workspace: {}", cwd.display());
    println!("permission mode: {}", options.permission_mode.as_str());
    println!("provider: {}", options.provider.as_str());
    println!("risk: {}", decision.risk);
    println!("requested action: {}", decision.requested_action);
    if let Some(target) = &decision.formal_target {
        println!("formal target: {}", target);
    }
    if let Some(command) = &decision.verification_command {
        println!("verification: {}", command);
    }
    println!("metacog: {} ({})", decision.verdict, decision.reason);
    if decision.verdict == "veto" || decision.verdict == "escalate" {
        return Err(anyhow!("metacog {}: {}", decision.verdict, decision.reason));
    }

    // Keep the human-facing shell path on the existing inference bridge. The
    // JSON adapter path stays event-clean for Zedge process parsing.
    if options.provider != AgentProvider::Sovereign {
        println!(
            "{}",
            run_account_provider(&options.provider, &cwd, &options.prompt, &decision)?
        );
        Ok(())
    } else if agent_tool_loop_enabled() || is_port_open(fat_station_port()).await {
        // The tool loop's brain has its own skymesh→fat-station fallback, so a
        // cold fat-station no longer forces the canned answer.
        let tool_index = if options.no_tools {
            None
        } else {
            load_agent_tool_index().await.ok()
        };
        handle_agent_chat(
            &options.prompt,
            config,
            tool_index.as_ref(),
            &mut Vec::new(),
            &mut None,
        )
        .await
    } else {
        println!("{}", agent_exec_answer(&options.prompt, &decision));
        Ok(())
    }
}

pub async fn run_agent_verify_command(args_line: &str) -> Result<()> {
    let options = parse_agent_verify_options(args_line)?;
    let cwd = options.cwd.clone().unwrap_or(std::env::current_dir()?);
    let workdir = resolve_gnosis_math_workdir(&cwd);
    let run_id = format!(
        "moonshine-agent-verify-{}",
        chrono::Utc::now().timestamp_millis()
    );
    let module = lean_module_from_target(&options.formal_target);
    let verification_command = format!("lake build {module}");

    if options.json {
        let mut start = AgentJsonEvent::new("run_start");
        start.run_id = Some(run_id.clone());
        start.workspace_path = Some(cwd.to_string_lossy().into_owned());
        start.prompt = Some(format!("verify {}", options.formal_target));
        start.requested_action = Some("Lean formal admission".to_string());
        start.risk = Some("formal_claim".to_string());
        start.formal_target = Some(options.formal_target.clone());
        start.verification_command = Some(verification_command.clone());
        print_agent_json_event(start)?;

        let mut request = AgentJsonEvent::new("tool_request");
        request.run_id = Some(run_id.clone());
        request.workspace_path = Some(cwd.to_string_lossy().into_owned());
        request.tool_name = Some("lean_build".to_string());
        request.command = Some(verification_command.clone());
        request.path = Some(workdir.to_string_lossy().into_owned());
        request.requested_action = Some("Lean formal admission".to_string());
        request.risk = Some("formal_claim".to_string());
        request.formal_target = Some(options.formal_target.clone());
        request.verification_command = Some(verification_command.clone());
        print_agent_json_event(request)?;

        let started = Instant::now();
        let output = Command::new("lake")
            .current_dir(&workdir)
            .arg("build")
            .arg(&module)
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .output();
        let duration_ms = started.elapsed().as_millis();

        let mut result = AgentJsonEvent::new("tool_result");
        result.run_id = Some(run_id.clone());
        result.workspace_path = Some(cwd.to_string_lossy().into_owned());
        result.tool_name = Some("lean_build".to_string());
        result.command = Some(verification_command.clone());
        result.path = Some(workdir.to_string_lossy().into_owned());
        result.requested_action = Some("Lean formal admission".to_string());
        result.risk = Some("formal_claim".to_string());
        result.duration_ms = Some(duration_ms);
        result.formal_target = Some(options.formal_target.clone());
        result.verification_command = Some(verification_command.clone());

        match output {
            Ok(output) => {
                result.status = Some(if output.status.success() {
                    "passed".to_string()
                } else {
                    "failed".to_string()
                });
                result.exit_code = output.status.code();
                let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
                let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
                let content = match (stdout.is_empty(), stderr.is_empty()) {
                    (false, false) => format!("{stdout}\n{stderr}"),
                    (false, true) => stdout,
                    (true, false) => stderr,
                    (true, true) => format!("{verification_command} completed with no output"),
                };
                result.content = Some(content.clone());
                print_agent_json_event(result)?;

                if output.status.success() {
                    let mut final_event = AgentJsonEvent::new("final");
                    final_event.run_id = Some(run_id);
                    final_event.workspace_path = Some(cwd.to_string_lossy().into_owned());
                    final_event.requested_action = Some("Lean formal admission".to_string());
                    final_event.risk = Some("formal_claim".to_string());
                    final_event.formal_target = Some(options.formal_target.clone());
                    final_event.verification_command = Some(verification_command.clone());
                    final_event.content = Some(format!(
                        "Lean verification passed for {}",
                        options.formal_target
                    ));
                    print_agent_json_event(final_event)?;
                    return Ok(());
                }

                let mut error = AgentJsonEvent::new("error");
                error.run_id = Some(run_id);
                error.workspace_path = Some(cwd.to_string_lossy().into_owned());
                error.requested_action = Some("Lean formal admission".to_string());
                error.risk = Some("formal_claim".to_string());
                error.formal_target = Some(options.formal_target.clone());
                error.verification_command = Some(verification_command.clone());
                error.error = Some(content);
                print_agent_json_event(error)?;
                Err(anyhow!(
                    "{} failed for {}",
                    verification_command,
                    options.formal_target
                ))
            }
            Err(err) => {
                result.status = Some("failed".to_string());
                result.error = Some(err.to_string());
                print_agent_json_event(result)?;

                let mut error = AgentJsonEvent::new("error");
                error.run_id = Some(run_id);
                error.workspace_path = Some(cwd.to_string_lossy().into_owned());
                error.requested_action = Some("Lean formal admission".to_string());
                error.risk = Some("formal_claim".to_string());
                error.formal_target = Some(options.formal_target.clone());
                error.verification_command = Some(verification_command);
                error.error = Some(err.to_string());
                print_agent_json_event(error)?;
                Err(anyhow!("agent verify could not run lake: {}", err))
            }
        }
    } else {
        println!("--- Moonshine Lean Verifier ---");
        println!("workspace: {}", cwd.display());
        println!("workdir: {}", workdir.display());
        println!("formal target: {}", options.formal_target);
        println!("verification: {}", verification_command);
        let output = Command::new("lake")
            .current_dir(&workdir)
            .arg("build")
            .arg(&module)
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .output()
            .map_err(|err| anyhow!("agent verify could not run lake: {}", err))?;
        let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
        let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
        if !stdout.is_empty() {
            println!("{stdout}");
        }
        if !stderr.is_empty() {
            eprintln!("{stderr}");
        }
        if output.status.success() {
            println!("Lean verification passed for {}", options.formal_target);
            Ok(())
        } else {
            Err(anyhow!(
                "{} failed for {}",
                verification_command,
                options.formal_target
            ))
        }
    }
}

pub async fn run_agent_providers_command(args_line: &str) -> Result<()> {
    let options = parse_agent_providers_options(args_line)?;
    let providers = [
        ("sovereign", true, "built-in Moonshine provider".to_string()),
        {
            let (available, detail) =
                command_status(&account_provider_program(&AgentProvider::Codex), &["--version"]);
            ("codex", available, detail)
        },
        {
            let (available, detail) =
                command_status(&account_provider_program(&AgentProvider::Claude), &["--version"]);
            ("claude", available, detail)
        },
    ];

    if options.json {
        for (provider, available, detail) in &providers {
            let mut event = AgentJsonEvent::new("provider_status");
            event.provider = Some((*provider).to_string());
            event.status = Some(if *available {
                "available".to_string()
            } else {
                "unavailable".to_string()
            });
            if !detail.trim().is_empty() {
                event.content = Some(detail.clone());
            }
            print_agent_json_event(event)?;
        }

        let available = providers
            .iter()
            .filter(|(_, available, _)| *available)
            .map(|(provider, _, _)| *provider)
            .collect::<Vec<_>>()
            .join(", ");
        let mut final_event = AgentJsonEvent::new("final");
        final_event.content = Some(format!("available providers: {available}"));
        print_agent_json_event(final_event)?;
        return Ok(());
    }

    println!("--- Moonshine Agent Providers ---");
    for (provider, available, detail) in &providers {
        let status = if *available {
            "available"
        } else {
            "unavailable"
        };
        if detail.trim().is_empty() {
            println!("{provider}: {status}");
        } else {
            println!("{provider}: {status} ({detail})");
        }
    }
    Ok(())
}

fn json_str<'a>(value: &'a serde_json::Value, key: &str) -> Option<&'a str> {
    value.get(key).and_then(serde_json::Value::as_str)
}

pub async fn run_agent_runs_command(args_line: &str) -> Result<()> {
    let options = parse_agent_runs_options(args_line)?;
    let cwd = options.cwd.clone().unwrap_or(std::env::current_dir()?);
    let dir = run_ledger_dir(&cwd);
    let mut entries = if dir.exists() {
        fs::read_dir(&dir)?
            .filter_map(|entry| entry.ok())
            .filter(|entry| entry.path().extension().and_then(|ext| ext.to_str()) == Some("jsonl"))
            .filter_map(|entry| {
                let modified = entry
                    .metadata()
                    .ok()
                    .and_then(|metadata| metadata.modified().ok())?;
                Some((entry.path(), modified))
            })
            .collect::<Vec<_>>()
    } else {
        Vec::new()
    };
    entries.sort_by(|(_, left), (_, right)| right.cmp(left));
    entries.truncate(options.limit);

    if options.json {
        for (path, _) in entries {
            let run_id = path
                .file_stem()
                .and_then(|stem| stem.to_str())
                .unwrap_or("unknown-run")
                .to_string();
            let content = fs::read_to_string(&path)?;
            let parsed = content
                .lines()
                .filter_map(|line| serde_json::from_str::<serde_json::Value>(line).ok())
                .collect::<Vec<_>>();
            let first = parsed.first();
            let has_final = parsed
                .iter()
                .any(|event| json_str(event, "type") == Some("final"));
            let has_error = parsed
                .iter()
                .any(|event| json_str(event, "type") == Some("error"));
            let status = if has_error {
                "failed"
            } else if has_final {
                "completed"
            } else {
                "pending"
            };
            let mut record = AgentJsonEvent::new("run_record");
            record.run_id = Some(run_id.clone());
            record.workspace_path = Some(cwd.to_string_lossy().into_owned());
            record.status = Some(status.to_string());
            if let Some(first) = first {
                record.provider = json_str(first, "provider").map(ToString::to_string);
                record.prompt = json_str(first, "prompt").map(ToString::to_string);
                record.formal_target = json_str(first, "formal_target").map(ToString::to_string);
                record.verification_command =
                    json_str(first, "verification_command").map(ToString::to_string);
            }
            record.content = Some(format!("{run_id}: {status}"));
            print_agent_json_event(record)?;
        }
        let mut final_event = AgentJsonEvent::new("final");
        final_event.workspace_path = Some(cwd.to_string_lossy().into_owned());
        final_event.content = Some(format!("{} run ledger record(s)", options.limit.min(
            fs::read_dir(&dir).map(|iter| iter.count()).unwrap_or(0)
        )));
        print_agent_json_event(final_event)?;
        return Ok(());
    }

    println!("--- Moonshine Agent Runs ---");
    if entries.is_empty() {
        println!("no recorded runs");
    }
    for (path, _) in entries {
        let run_id = path
            .file_stem()
            .and_then(|stem| stem.to_str())
            .unwrap_or("unknown-run");
        println!("{run_id}");
    }
    Ok(())
}

