pub async fn run_agent_tools_command(args_line: &str) -> Result<()> {
    let options = parse_agent_tools_options(args_line)?;
    let cwd = options.cwd.clone().unwrap_or(std::env::current_dir()?);
    let base = cwd.join(TOOL_INTENT_DIR);
    let mut records = Vec::new();
    if let Some(run_id) = &options.run_id {
        let dir = tool_intent_dir(&cwd, run_id);
        if dir.exists() {
            for entry in fs::read_dir(dir)?.filter_map(|entry| entry.ok()) {
                if entry.path().extension().and_then(|ext| ext.to_str()) != Some("json") {
                    continue;
                }
                if let Ok(bytes) = fs::read(entry.path()) {
                    if let Ok(record) = serde_json::from_slice::<ToolIntentRecord>(&bytes) {
                        records.push(record);
                    }
                }
            }
        }
    } else if base.exists() {
        for run_dir in fs::read_dir(base)?.filter_map(|entry| entry.ok()) {
            if !run_dir.path().is_dir() {
                continue;
            }
            for entry in fs::read_dir(run_dir.path())?.filter_map(|entry| entry.ok()) {
                if entry.path().extension().and_then(|ext| ext.to_str()) != Some("json") {
                    continue;
                }
                if let Ok(bytes) = fs::read(entry.path()) {
                    if let Ok(record) = serde_json::from_slice::<ToolIntentRecord>(&bytes) {
                        records.push(record);
                    }
                }
            }
        }
    }
    records.sort_by(|left, right| right.created_at.cmp(&left.created_at));
    records.truncate(options.limit);

    if options.json {
        for record in &records {
            let kind = if record.status == "denied" {
                "tool_denial"
            } else {
                "tool_admission"
            };
            print_agent_json_event(tool_event_from_record(kind, record))?;
        }
        let mut final_event = AgentJsonEvent::new("final");
        final_event.workspace_path = Some(cwd.to_string_lossy().into_owned());
        final_event.content = Some(format!("{} tool intent record(s)", records.len()));
        print_agent_json_event(final_event)?;
        return Ok(());
    }

    println!("--- Moonshine Agent Tools ---");
    if records.is_empty() {
        println!("no tool intents");
    }
    for record in &records {
        println!(
            "{} {} {} {}",
            record.run_id, record.intent_id, record.status, record.requested_action
        );
    }
    Ok(())
}

