async fn run_agent_tool_decision_command(
    args_line: &str,
    command_name: &str,
    approve: bool,
) -> Result<()> {
    let options = parse_agent_tool_decision_options(args_line, command_name)?;
    let cwd = options.cwd.clone().unwrap_or(std::env::current_dir()?);
    let mut record = load_tool_intent(&cwd, &options.run_id, &options.intent_id)?;
    record.status = if approve {
        "approved".to_string()
    } else {
        "denied".to_string()
    };
    persist_tool_intent(&cwd, &record)?;
    let ledger_path = run_ledger_path(&cwd, &record.run_id);
    let kind = if approve { "tool_admission" } else { "tool_denial" };
    let event = tool_event_from_record(kind, &record);
    if options.json {
        emit_agent_json_event(event, Some(&ledger_path))?;
        let mut final_event = AgentJsonEvent::new("final");
        final_event.run_id = Some(record.run_id.clone());
        final_event.workspace_path = Some(record.workspace_path.clone());
        final_event.intent_id = Some(record.intent_id.clone());
        final_event.tool_name = Some(record.tool_name.clone());
        final_event.status = Some(record.status.clone());
        final_event.content = Some(format!(
            "{} {}",
            record.intent_id,
            if approve { "approved" } else { "denied" }
        ));
        emit_agent_json_event(final_event, Some(&ledger_path))?;
        return Ok(());
    }
    println!(
        "{} {}",
        record.intent_id,
        if approve { "approved" } else { "denied" }
    );
    Ok(())
}

pub async fn run_agent_resume_command(args_line: &str) -> Result<()> {
    let options = parse_agent_resume_options(args_line)?;
    let cwd = options.cwd.clone().unwrap_or(std::env::current_dir()?);
    let record = load_permission_record(&cwd, &options.run_id)?;

    if options.json {
        let mut decision_event = AgentJsonEvent::new("permission_decision");
        decision_event.run_id = Some(record.run_id.clone());
        decision_event.workspace_path = Some(record.workspace_path.clone());
        decision_event.permission_mode = Some(record.permission_mode.clone());
        decision_event.provider = Some(record.provider.clone());
        decision_event.verdict = Some(record.verdict.clone());
        decision_event.reason = Some(record.reason.clone());
        decision_event.requested_action = Some(record.requested_action.clone());
        decision_event.risk = Some(record.risk.clone());
        decision_event.formal_target = record.formal_target.clone();
        decision_event.verification_command = record.verification_command.clone();
        decision_event.status = Some(options.decision.as_str().to_string());
        print_agent_json_event(decision_event)?;

        match options.decision {
            ResumeDecision::Approve => {
                remove_permission_record(&cwd, &record.run_id)?;
                let mut final_event = AgentJsonEvent::new("final");
                final_event.run_id = Some(record.run_id);
                final_event.workspace_path = Some(record.workspace_path);
                final_event.permission_mode = Some(record.permission_mode);
                final_event.provider = Some(record.provider.clone());
                final_event.formal_target = record.formal_target.clone();
                final_event.verification_command = record.verification_command.clone();
                final_event.content = Some(format!(
                    "Moonshine agent resumed after human approval for {}. Prompt: {}",
                    record.requested_action, record.prompt
                ));
                print_agent_json_event(final_event)?;
                Ok(())
            }
            ResumeDecision::Deny => {
                remove_permission_record(&cwd, &record.run_id)?;
                let mut error = AgentJsonEvent::new("error");
                error.run_id = Some(record.run_id);
                error.workspace_path = Some(record.workspace_path);
                error.permission_mode = Some(record.permission_mode);
                error.provider = Some(record.provider.clone());
                error.verdict = Some("veto".to_string());
                error.reason = Some("human denied permission request".to_string());
                error.requested_action = Some(record.requested_action);
                error.risk = Some(record.risk);
                error.formal_target = record.formal_target.clone();
                error.verification_command = record.verification_command.clone();
                error.error = Some("human denied permission request".to_string());
                print_agent_json_event(error)?;
                Err(anyhow!("human denied permission request"))
            }
        }
    } else {
        println!("run: {}", record.run_id);
        println!("requested action: {}", record.requested_action);
        println!("risk: {}", record.risk);
        println!("decision: {}", options.decision.as_str());
        remove_permission_record(&cwd, &record.run_id)?;
        if options.decision == ResumeDecision::Deny {
            Err(anyhow!("human denied permission request"))
        } else {
            Ok(())
        }
    }
}

pub async fn run_agent_metacog_command(args_line: &str) -> Result<()> {
    let words = shlex::split(args_line)
        .ok_or_else(|| anyhow!("agent metacog: could not parse quoted arguments"))?;
    let mut json = false;
    let mut rest: Vec<String> = Vec::new();
    let mut i = 0;
    while i < words.len() {
        match words[i].as_str() {
            "--json" => {
                json = true;
                i += 1;
            }
            "--" => {
                rest.extend(words[i + 1..].iter().cloned());
                break;
            }
            flag if flag.starts_with("--") => {
                return Err(anyhow!("agent metacog: unsupported flag '{}'", flag));
            }
            _ => {
                rest.extend(words[i..].iter().cloned());
                break;
            }
        }
    }

    let input = rest.join(" ");
    if input.trim().is_empty() {
        return Err(anyhow!(
            "agent metacog: event log text or a path to an event log is required"
        ));
    }
    let event_log = {
        let path = PathBuf::from(input.trim());
        if path.exists() {
            std::fs::read_to_string(&path)?
        } else {
            input
        }
    };
    let decision = decide_metacog(&event_log);
    if json {
        let mut event = AgentJsonEvent::new("metacog_verdict");
        event.verdict = Some(decision.verdict.to_string());
        event.reason = Some(decision.reason.clone());
        event.requested_action = Some(decision.requested_action.to_string());
        event.risk = Some(decision.risk.to_string());
        attach_formal_metadata(&mut event, &decision);
        print_agent_json_event(event)?;
    } else {
        println!("{}: {}", decision.verdict, decision.reason);
    }
    Ok(())
}

